const items = $input.all().map(i => i.json);

// Group orders by business_id
const grouped = {};
for (const order of items) {
  const key = order.business_id;
  if (!grouped[key]) {
    grouped[key] = {
      business_id:       order.business_id,
      business_name:     order.business_name,
      owner_telegram_id: order.owner_telegram_id,
      owner_name:        order.owner_name,
      bot_token:         order.bot_token,
      orders:            []
    };
  }
  grouped[key].orders.push({
    order_number:         order.order_number,
    status:               order.status,
    total_amount:         order.total_amount,
    items:                order.items,
    delivery_type:        order.delivery_type,
    appointment_datetime: order.appointment_datetime,
    customer_notes:       order.customer_notes,
    customer_chat_id:     order.customer_chat_id,
    hours_waiting:        Math.round(order.hours_waiting * 10) / 10
  });
}

// Return one item per business
return Object.values(grouped).map(biz => ({ json: biz }));

const biz = $input.item.json;
const orders = biz.orders;

const orderLines = orders.map(o => {
  let itemsText = '';
  try {
    const parsed = typeof o.items === 'string' ? JSON.parse(o.items) : o.items;
    if (Array.isArray(parsed)) {
      itemsText = parsed.map(i => (i.quantity || 1) + 'x ' + i.name).join(', ');
    }
  } catch(e) {}

  let timeLabel = '';
  if (o.hours_waiting < 24) {
    timeLabel = Math.round(o.hours_waiting) + 'h ago';
  } else {
    timeLabel = Math.round(o.hours_waiting / 24) + 'd ago';
  }

  let appointmentText = '';
  if (o.appointment_datetime) {
    try {
      const dt = new Date(o.appointment_datetime);
      appointmentText = ' | ' + dt.toLocaleString('en-NG', {
        timeZone: 'Africa/Lagos',
        weekday: 'short', month: 'short', day: 'numeric',
        hour: '2-digit', minute: '2-digit'
      });
    } catch(e) {}
  }

  const statusEmoji = o.status === 'enquiry' ? '💬' : '🛒';

  return `${statusEmoji} *${o.order_number}* — ${timeLabel}\n` +
         (itemsText ? `Items: ${itemsText}\n` : '') +
         (o.total_amount ? `Total: ₦${Number(o.total_amount).toLocaleString()}\n` : '') +
         (appointmentText ? `Appointment:${appointmentText}\n` : '') +
         (o.customer_notes ? `Notes: ${o.customer_notes}\n` : '');
}).join('\n');

const count = orders.length;
const plural = count === 1 ? 'order' : 'orders';

const message = `⏰ *${count} unattended ${plural} need your attention!*\n\n` +
  orderLines +
  `\nReply to each customer or confirm via your bot to clear these.`;

return {
  json: {
    bot_token:         biz.bot_token,
    owner_telegram_id: biz.owner_telegram_id,
    business_name:     biz.business_name,
    message
  }
};
